mapper.select:
	/*
		 SQL ID : SysFileRepoDAO.count
		 설  명 : 파일 리파지토리의 페이징 카운트
 	*/
 	SELECT COUNT(*) FROM (

 	) T

		/*
			 SQL ID : SysFileRepoDAO.select
			 설  명 : 파일 리파지토리의 정보 조회
	 	*/

           AND A.ATFL_REPO_ID = #{repoCd}

mapper.insert:
	/*
		 SQL ID : SysFileRepoDAO.insert
		 설  명 : 파일 리파지토리의 정보 등록
 	*/
 	INSERT INTO TB_LMS_ATFL_REPO (
	       ATFL_REPO_ID
	     , ATFL_REPO_PATH
	     , UP_CLMNNM
	     , UP_TBLNM
	     , RGTRNM
	     , RGTR_ID
	     , REG_DTTM
	) VALUES (
	       #{repoCd}
	     , #{repoDfltPath}
	     , #{parFieldNm}
	     , #{parTableNm}
	     , #{regNm}
	     , #{rgtrId}
	     , TO_CHAR(SYSDATE,'yyyymmddhh24miss')
	)

mapper.update:
	/*
		 SQL ID : SysFileRepoDAO.update
		 설  명 : 파일 리파지토리의 정보 수정
 	*/
	UPDATE TB_LMS_ATFL_REPO
	   SET ATFL_REPO_ID = #{repoCd}
	     , UP_TBLNM = #{parTableNm}
	     , UP_CLMNNM = #{parFieldNm}
	     , ATFL_REPO_PATH  = #{repoDfltPath}
	 WHERE ATFL_REPO_ID = #{repoCd}

mapper.delete:
	/*
		 SQL ID : SysFileRepoDAO.delete
		 설  명 : 파일 리파지토리의 정보 삭제
 	*/
	DELETE FROM TB_LMS_ATFL_REPO
	 WHERE ATFL_REPO_ID = #{repoCd}
